import json
import time
import random
from datetime import datetime, timezone

def generate_system_data(system_id: str):
    cpu_usage = round(random.uniform(10.0, 95.0), 2)
    memory_usage = round(random.uniform(20.0, 98.0), 2)
    disk_usage = round(random.uniform(5.0, 99.0), 2)
    network_in = round(random.uniform(0.1, 50.0), 2)
    network_out = round(random.uniform(0.1, 20.0), 2)
    request_latency = round(random.uniform(10.0, 500.0), 2)
    error_rate = round(random.uniform(0.0, 10.0), 2)
    active_connections = random.randint(10, 10000)

    services = {
        "auth_service": random.choices(["running", "stopped", "error"], weights=[0.90, 0.05, 0.05], k=1)[0],
        "database_service": random.choices(["running", "stopped", "error"], weights=[0.92, 0.03, 0.05], k=1)[0],
        "web_server": random.choices(["running", "stopped", "error"], weights=[0.95, 0.02, 0.03], k=1)[0],
        "api_gateway": random.choices(["running", "stopped", "error"], weights=[0.93, 0.04, 0.03], k=1)[0],
    }

    overall_status = "operational"
    if cpu_usage > 90 or memory_usage > 95 or disk_usage > 98 or error_rate > 5:
        overall_status = "critical"
    elif cpu_usage > 75 or memory_usage > 85 or disk_usage > 90 or error_rate > 2:
        overall_status = "warning"
    elif any(s in ["stopped", "error"] for s in services.values()):
        overall_status = "warning"

    if random.random() < 0.005:
        overall_status = "critical"
    elif random.random() < 0.01:
        overall_status = "maintenance"

    log_level_counts = {
        "info": random.randint(100, 10000),
        "warn": random.randint(10, 500),
        "error": random.randint(1, 100),
        "critical": random.randint(0, 10)
    }

    alerts = []
    if overall_status == "critical":
        alerts.append({"severity": "critical", "message": f"System {system_id} is in a critical state!"})
    if cpu_usage > 90:
        alerts.append({"severity": "warning", "message": f"High CPU usage ({cpu_usage}%) on {system_id}"})
    if memory_usage > 95:
        alerts.append({"severity": "critical", "message": f"Memory exhaustion ({memory_usage}%) on {system_id}"})
    if disk_usage > 98:
        alerts.append({"severity": "critical", "message": f"Disk almost full ({disk_usage}%) on {system_id}"})
    if error_rate > 3:
        alerts.append({"severity": "warning", "message": f"Elevated error rate ({error_rate}%) on {system_id}"})
    for service_name, status in services.items():
        if status == "stopped":
            alerts.append({"severity": "critical", "message": f"Service '{service_name}' on {system_id} is stopped"})
        elif status == "error":
            alerts.append({"severity": "warning", "message": f"Service '{service_name}' on {system_id} is reporting errors"})
    if log_level_counts["critical"] > 0:
        alerts.append({"severity": "critical", "message": f"Critical log events detected on {system_id}: {log_level_counts['critical']} events"})

    data = {
        "timestamp": datetime.now(timezone.utc).isoformat(timespec='seconds'),
        "system_id": system_id,
        "overall_status": overall_status,
        "metrics": {
            "cpu_usage_percent": cpu_usage,
            "memory_usage_percent": memory_usage,
            "disk_usage_percent": disk_usage,
            "network_in_mbps": network_in,
            "network_out_mbps": network_out,
            "request_latency_ms": request_latency,
            "error_rate_percent": error_rate,
            "active_connections": active_connections,
            "log_level_counts": log_level_counts
        },
        "services": services,
        "alerts": alerts
    }
    return data

def main():
    systems = ["frontend-web-01", "frontend-web-02", "backend-api-01", "backend-api-02", "database-01", "message-queue-01"]

    while True:
        for system_id in systems:
            data_point = generate_system_data(system_id)
            print(json.dumps(data_point))
        time.sleep(1)

if __name__ == "__main__":
    main()
